@abstract
class Vehicle:
    """Abstract base class for vehicles."""
    make: str
    model: str
    year: int

    def __init__(self, make: str, model: str, year: int):
        self.make = make
        self.model = model
        self.year = year

    @abstract
    def describe(self) -> str:
        ...

    def display_name(self) -> str:
        return self.make + " " + self.model

