from vehicles import Vehicle

class Car(Vehicle):
    doors: int
    trunk_capacity: float

    def __init__(self, make: str, model: str, year: int, doors: int):
        super().__init__(make, model, year)
        self.doors = doors
        self.trunk_capacity = 15.5

    def vehicle_type(self) -> str:
        return "Car"

    def describe(self) -> str:
        return str(self.doors) + "-door " + self.display_name()

class Truck(Vehicle):
    bed_length: float
    towing_capacity: int

    def __init__(self, make: str, model: str, year: int, bed_length: float):
        super().__init__(make, model, year)
        self.bed_length = bed_length
        self.towing_capacity = 5000

    def vehicle_type(self) -> str:
        return "Truck"

    def describe(self) -> str:
        return self.display_name() + " with " + str(self.bed_length) + " ft bed"

